const BlockInfo = function(blockId, src, hp=1, color=null, itemInfo=null, itemCount=1) {
    let img = new Image();
    img.src = src;
    
    this.sprite = img;
    this.id = blockId;
    this.hp = hp;
    this.itemInfo = itemInfo;
    this.color = color;
    this.itemCount = itemCount;

    return this;
};

